const upsertCourseTemplateVersionQuiz = `-- name: UpsertCourseTemplateVersionQuiz :one
WITH target AS (
    SELECT lesson.company_id, lesson.template_version_id, lesson.id AS lesson_id
    FROM course_template_version_lessons AS lesson
    JOIN course_template_versions AS version
      ON version.company_id = lesson.company_id
     AND version.id = lesson.template_version_id
    JOIN course_templates AS template
      ON template.company_id = version.company_id
     AND template.id = version.template_id
    WHERE lesson.company_id = $1
      AND lesson.id = $2
      AND version.status = 'draft'
      AND template.template_type = 'company'
      AND template.lifecycle_status = 'active'
), saved AS (
    INSERT INTO course_template_version_quizzes (
        id, company_id, template_version_id, lesson_version_id,
        questions, passing_score, max_attempts
    ) SELECT $3, target.company_id, target.template_version_id,
        target.lesson_id, $4, $5,
        $6
    FROM target
    ON CONFLICT (lesson_version_id) DO UPDATE
    SET questions = EXCLUDED.questions,
        passing_score = EXCLUDED.passing_score,
        max_attempts = EXCLUDED.max_attempts
    RETURNING id, company_id, template_version_id, lesson_version_id,
        questions, passing_score, max_attempts
), linked AS (
    UPDATE course_template_version_lessons AS lesson
    SET quiz_version_id = saved.id
    FROM saved WHERE lesson.id = saved.lesson_version_id
)
SELECT id, company_id, template_version_id, lesson_version_id,
    questions, passing_score, max_attempts
FROM saved
`

type UpsertCourseTemplateVersionQuizParams struct {
	CompanyID       uuid.UUID   `json:"company_id"`
	LessonVersionID uuid.UUID   `json:"lesson_version_id"`
	ID              uuid.UUID   `json:"id"`
	Questions       []byte      `json:"questions"`
	PassingScore    int32       `json:"passing_score"`
	MaxAttempts     pgtype.Int4 `json:"max_attempts"`
}

type UpsertCourseTemplateVersionQuizRow struct {
	ID                uuid.UUID   `json:"id"`
	CompanyID         uuid.UUID   `json:"company_id"`
	TemplateVersionID uuid.UUID   `json:"template_version_id"`
	LessonVersionID   uuid.UUID   `json:"lesson_version_id"`
	Questions         []byte      `json:"questions"`
	PassingScore      int32       `json:"passing_score"`
	MaxAttempts       pgtype.Int4 `json:"max_attempts"`
}

func (q *Queries) UpsertCourseTemplateVersionQuiz(ctx context.Context, arg UpsertCourseTemplateVersionQuizParams) (UpsertCourseTemplateVersionQuizRow, error) {
	row := q.db.QueryRow(ctx, upsertCourseTemplateVersionQuiz,
		arg.CompanyID,
		arg.LessonVersionID,
		arg.ID,
		arg.Questions,
		arg.PassingScore,
		arg.MaxAttempts,
	)
	var i UpsertCourseTemplateVersionQuizRow
	err := row.Scan(
		&i.ID,
		&i.CompanyID,
		&i.TemplateVersionID,
		&i.LessonVersionID,
		&i.Questions,
		&i.PassingScore,
		&i.MaxAttempts,
	)
	return i, err
}
